-- Wrong:
SELECT * FROM users u LEFT JOIN orders o ON u.id = o.user_id WHERE o.status = 'active';
-- Right:
SELECT * FROM users u LEFT JOIN orders o ON u.id = o.user_id AND o.status = 'active';

-- Broken: NOT IN with possible NULLs
SELECT * FROM users WHERE id NOT IN (SELECT user_id FROM orders);
-- Fixed: NOT EXISTS
SELECT * FROM users u WHERE NOT EXISTS (SELECT 1 FROM orders o WHERE o.user_id = u.id);

