# Drizzle Setup and Schema Definition

## Introduction

Drizzle ORM is a lightweight, type-safe SQL-first ORM for TypeScript. Unlike Prisma which uses its own schema language, Drizzle schemas are pure TypeScript — your table definitions are TypeScript code that doubles as the type system. Drizzle generates minimal overhead, produces efficient SQL, and gives you full control while maintaining type safety.

## Why Drizzle?

```
Prisma:   Schema file -> Generated client -> Runtime query engine
Drizzle:  TypeScript schema -> Direct SQL generation -> pg driver

Drizzle advantages:
- No code generation step (schema IS the types)
- No separate runtime engine
- SQL-like API (if you know SQL, you know Drizzle)
- Smaller bundle size
- Serverless-friendly (no binary dependencies)
```

## Installation

```bash
npm install drizzle-orm pg
npm install -D drizzle-kit @types/pg
```

## Schema Definition

```typescript
// src/db/schema.ts
import {
  pgTable, serial, text, varchar, integer, boolean,
  timestamp, decimal, uuid, jsonb, pgEnum,
  uniqueIndex, index,
} from 'drizzle-orm/pg-core';
import { relations } from 'drizzle-orm';

// Enums
export const roleEnum = pgEnum('role', ['customer', 'admin', 'vendor']);
export const orderStatusEnum = pgEnum('order_status', [
  'pending', 'processing', 'shipped', 'delivered', 'cancelled',
]);

// Users table
export const users = pgTable('users', {
  id: uuid('id').primaryKey().defaultRandom(),
  email: varchar('email', { length: 320 }).notNull().unique(),
  name: text('name').notNull(),
  passwordHash: text('password_hash').notNull(),
  role: roleEnum('role').notNull().default('customer'),
  createdAt: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
  updatedAt: timestamp('updated_at', { withTimezone: true }).notNull().defaultNow(),
  deletedAt: timestamp('deleted_at', { withTimezone: true }),
}, (table) => ({
  emailIdx: uniqueIndex('idx_users_email').on(table.email),
}));

// Products table
export const products = pgTable('products', {
  id: uuid('id').primaryKey().defaultRandom(),
  name: text('name').notNull(),
  slug: text('slug').notNull().unique(),
  description: text('description'),
  price: decimal('price', { precision: 10, scale: 2 }).notNull(),
  stock: integer('stock').notNull().default(0),
  categoryId: uuid('category_id').references(() => categories.id),
  isActive: boolean('is_active').notNull().default(true),
  metadata: jsonb('metadata').default({}),
  tags: text('tags').array(),
  createdAt: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
}, (table) => ({
  categoryIdx: index('idx_products_category').on(table.categoryId),
  activeIdx: index('idx_products_active').on(table.isActive),
}));

// Categories (self-referencing)
export const categories = pgTable('categories', {
  id: uuid('id').primaryKey().defaultRandom(),
  name: text('name').notNull(),
  slug: text('slug').notNull().unique(),
  parentId: uuid('parent_id').references((): any => categories.id),
});

// Orders
export const orders = pgTable('orders', {
  id: uuid('id').primaryKey().defaultRandom(),
  userId: uuid('user_id').notNull().references(() => users.id),
  status: orderStatusEnum('status').notNull().default('pending'),
  total: decimal('total', { precision: 10, scale: 2 }).notNull(),
  createdAt: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
}, (table) => ({
  userIdx: index('idx_orders_user').on(table.userId),
}));

// Order Items
export const orderItems = pgTable('order_items', {
  id: serial('id').primaryKey(),
  orderId: uuid('order_id').notNull().references(() => orders.id, { onDelete: 'cascade' }),
  productId: uuid('product_id').notNull().references(() => products.id),
  quantity: integer('quantity').notNull(),
  unitPrice: decimal('unit_price', { precision: 10, scale: 2 }).notNull(),
});
```

## Defining Relations

```typescript
// src/db/relations.ts
import { relations } from 'drizzle-orm';
import { users, orders, orderItems, products, categories } from './schema';

export const usersRelations = relations(users, ({ many }) => ({
  orders: many(orders),
}));

export const ordersRelations = relations(orders, ({ one, many }) => ({
  user: one(users, {
    fields: [orders.userId],
    references: [users.id],
  }),
  items: many(orderItems),
}));

export const orderItemsRelations = relations(orderItems, ({ one }) => ({
  order: one(orders, {
    fields: [orderItems.orderId],
    references: [orders.id],
  }),
  product: one(products, {
    fields: [orderItems.productId],
    references: [products.id],
  }),
}));

export const productsRelations = relations(products, ({ one, many }) => ({
  category: one(categories, {
    fields: [products.categoryId],
    references: [categories.id],
  }),
  orderItems: many(orderItems),
}));

export const categoriesRelations = relations(categories, ({ one, many }) => ({
  parent: one(categories, {
    fields: [categories.parentId],
    references: [categories.id],
    relationName: 'categoryTree',
  }),
  children: many(categories, { relationName: 'categoryTree' }),
  products: many(products),
}));
```

## Database Connection

```typescript
// src/db/index.ts
import { drizzle } from 'drizzle-orm/node-postgres';
import { Pool } from 'pg';
import * as schema from './schema';
import * as relations from './relations';

const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  max: 10,
});

export const db = drizzle(pool, {
  schema: { ...schema, ...relations },
  logger: process.env.NODE_ENV === 'development',
});

export type Database = typeof db;
```

## Drizzle Config

```typescript
// drizzle.config.ts
import { defineConfig } from 'drizzle-kit';

export default defineConfig({
  schema: './src/db/schema.ts',
  out: './drizzle',
  dialect: 'postgresql',
  dbCredentials: {
    url: process.env.DATABASE_URL!,
  },
});
```

## Type Inference

```typescript
import { InferSelectModel, InferInsertModel } from 'drizzle-orm';
import { users, products } from './schema';

// Infer types from schema (no code generation!)
export type User = InferSelectModel<typeof users>;
export type NewUser = InferInsertModel<typeof users>;
export type Product = InferSelectModel<typeof products>;
export type NewProduct = InferInsertModel<typeof products>;

// User type automatically has:
// { id: string, email: string, name: string, role: 'customer' | 'admin' | 'vendor', ... }
```

